```csharp
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Authorization;
using System.Data.SqlClient;
using System.Security.Claims;
using Microsoft.Extensions.Logging;

namespace DocumentApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize]
    public class DocumentsController : ControllerBase
    {
        private readonly string _connectionString;
        private readonly ILogger<DocumentsController> _logger;

        public DocumentsController(IConfiguration config, ILogger<DocumentsController> logger)
        {
            _connectionString = config.GetConnectionString("DefaultConnection");
            _logger = logger;
        }

        [HttpGet("{documentId}")]
        public IActionResult GetDocument(int documentId)
        {
            // Extract authenticated user's ID from JWT claims
            var userIdClaim = User.FindFirst(ClaimTypes.NameIdentifier)?.Value;
            if (string.IsNullOrEmpty(userIdClaim) || !int.TryParse(userIdClaim, out int currentUserId))
            {
                _logger.LogWarning("Invalid user claim in token");
                return Unauthorized();
            }

            using var connection = new SqlConnection(_connectionString);
            connection.Open();

            // SECURE: Query includes ownership check in WHERE clause
            var cmd = new SqlCommand(
                @"SELECT Id, Title, Content FROM Documents 
                  WHERE Id = @Id AND OwnerId = @OwnerId",
                connection);
            cmd.Parameters.AddWithValue("@Id", documentId);
            cmd.Parameters.AddWithValue("@OwnerId", currentUserId);

            using var reader = cmd.ExecuteReader();
            if (reader.Read())
            {
                _logger.LogInformation(
                    "User {UserId} accessed document {DocumentId}",
                    currentUserId, documentId);

                return Ok(new {
                    Id = reader.GetInt32(0),
                    Title = reader.GetString(1),
                    Content = reader.GetString(2)
                });
            }

            // Log potential IDOR attempt
            _logger.LogWarning(
                "User {UserId} attempted to access document {DocumentId} - not found or unauthorized",
                currentUserId, documentId);

            // Return 404 instead of 403 to prevent enumeration
            return NotFound();
        }
    }
}
```

**Key Security Controls**:
- **Ownership verification in query**: The WHERE clause includes `OwnerId = @OwnerId`, ensuring users can only retrieve their own documents
- **User ID from trusted source**: The user ID comes from the authenticated JWT claims, not from user input
- **Consistent error responses**: Returns 404 for both "not found" and "not authorized" to prevent enumeration attacks
- **Audit logging**: All access attempts are logged for security monitoring

