**PRODUCTION PATTERN**:

```csharp
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Authorization;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using System.Security.Claims;

namespace DocumentApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize]
    public class DocumentsController : ControllerBase
    {
        private readonly DocumentDbContext _context;
        private readonly ILogger<DocumentsController> _logger;
        private readonly IAuthorizationService _authService;

        public DocumentsController(
            DocumentDbContext context,
            ILogger<DocumentsController> logger,
            IAuthorizationService authService)
        {
            _context = context;
            _logger = logger;
            _authService = authService;
        }

        [HttpGet("{documentId}")]
        public async Task<IActionResult> GetDocument(Guid documentId)
        {
            var currentUserId = GetCurrentUserId();
            if (currentUserId == null)
                return Unauthorized();

            // Fetch document with access information
            var document = await _context.Documents
                .Include(d => d.DocumentShares)
                .FirstOrDefaultAsync(d => d.Id == documentId);

            if (document == null)
            {
                _logger.LogInformation(
                    "Document {DocumentId} not found - requested by user {UserId}",
                    documentId, currentUserId);
                return NotFound();
            }

            // Check authorization using policy-based authorization
            var authResult = await _authService.AuthorizeAsync(
                User, document, "DocumentAccess");

            if (!authResult.Succeeded)
            {
                _logger.LogWarning(
                    "SECURITY: User {UserId} unauthorized access attempt to document {DocumentId} owned by {OwnerId}",
                    currentUserId, documentId, document.OwnerId);

                // Return 404 to prevent enumeration
                return NotFound();
            }

            _logger.LogInformation(
                "User {UserId} accessed document {DocumentId} with permission {Permission}",
                currentUserId, documentId, GetAccessLevel(document, currentUserId.Value));

            return Ok(new DocumentResponse
            {
                Id = document.Id,
                Title = document.Title,
                Content = document.Content,
                AccessLevel = GetAccessLevel(document, currentUserId.Value)
            });
        }

        private Guid? GetCurrentUserId()
        {
            var claim = User.FindFirst(ClaimTypes.NameIdentifier)?.Value;
            return Guid.TryParse(claim, out var id) ? id : null;
        }

        private string GetAccessLevel(Document doc, Guid userId)
        {
            if (User.IsInRole("Admin")) return "admin";
            if (doc.OwnerId == userId) return "owner";
            return doc.DocumentShares
                .FirstOrDefault(s => s.UserId == userId)?.Permission ?? "none";
        }
    }

    // Authorization handler for document access
    public class DocumentAccessHandler : AuthorizationHandler<DocumentAccessRequirement, Document>
    {
        protected override Task HandleRequirementAsync(
            AuthorizationHandlerContext context,
            DocumentAccessRequirement requirement,
            Document document)
        {
            var userId = context.User.FindFirst(ClaimTypes.NameIdentifier)?.Value;
            if (string.IsNullOrEmpty(userId) || !Guid.TryParse(userId, out var userGuid))
            {
                context.Fail();
                return Task.CompletedTask;
            }

            // Layer 1: Admin bypass (with audit)
            if (context.User.IsInRole("Admin"))
            {
                context.Succeed(requirement);
                return Task.CompletedTask;
            }

            // Layer 2: Owner check
            if (document.OwnerId == userGuid)
            {
                context.Succeed(requirement);
                return Task.CompletedTask;
            }

            // Layer 3: Explicit share check
            var share = document.DocumentShares?
                .FirstOrDefault(s => s.UserId == userGuid && s.IsActive);

            if (share != null && !share.IsExpired())
            {
                context.Succeed(requirement);
                return Task.CompletedTask;
            }

            // Layer 4: Organization/team membership (if applicable)
            // Additional checks can be added here

            context.Fail();
            return Task.CompletedTask;
        }
    }

    // Entity models
    public class Document
    {
        public Guid Id { get; set; }
        public string Title { get; set; }
        public string Content { get; set; }
        public Guid OwnerId { get; set; }
        public DateTime CreatedAt { get; set; }
        public ICollection<DocumentShare> DocumentShares { get; set; }
    }

    public class DocumentShare
    {
        public Guid Id { get; set; }
        public Guid DocumentId { get; set; }
        public Guid UserId { get; set; }
        public string Permission { get; set; } // "read", "write", "admin"
        public bool IsActive { get; set; }
        public DateTime? ExpiresAt { get; set; }
        public Guid SharedByUserId { get; set; }
        public DateTime SharedAt { get; set; }

        public bool IsExpired() => ExpiresAt.HasValue && ExpiresAt < DateTime.UtcNow;
    }

    public class DocumentAccessRequirement : IAuthorizationRequirement { }

    public class DocumentResponse
    {
        public Guid Id { get; set; }
        public string Title { get; set; }
        public string Content { get; set; }
        public string AccessLevel { get; set; }
    }
}
```

