**SECURE VERSION**:

```javascript
const express = require('express');
const mysql = require('mysql2/promise');
const jwt = require('jsonwebtoken');

const app = express();
app.use(express.json());

const JWT_SECRET = process.env.JWT_SECRET;

// Authentication middleware
const authenticate = (req, res, next) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Missing authentication token' });
  }

  try {
    const token = authHeader.split(' ')[1];
    const decoded = jwt.verify(token, JWT_SECRET);
    req.user = decoded; // Contains verified user ID from token
    next();
  } catch (error) {
    return res.status(401).json({ error: 'Invalid token' });
  }
};

// SECURE: Use authenticated user's ID from JWT, not URL parameter
app.get('/api/orders', authenticate, async (req, res) => {
  // Get user ID from verified JWT token, NOT from request
  const authenticatedUserId = req.user.userId;

  try {
    const connection = await mysql.createConnection({
      host: process.env.DB_HOST,
      user: process.env.DB_USER,
      password: process.env.DB_PASSWORD,
      database: process.env.DB_NAME
    });

    // SECURE: Query uses authenticated user's ID
    const [orders] = await connection.execute(
      'SELECT order_id, product_name, quantity, total, created_at FROM orders WHERE user_id = ?',
      [authenticatedUserId]
    );

    await connection.end();

    // Log access for audit trail
    console.log(`User ${authenticatedUserId} accessed their orders at ${new Date().toISOString()}`);

    res.json({ orders });
  } catch (error) {
    console.error(`Database error for user ${authenticatedUserId}:`, error.message);
    res.status(500).json({ error: 'Unable to retrieve orders' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Identity from token**: User ID extracted from cryptographically verified JWT, not user input
- **No user-controllable resource identifiers**: Removed userId from URL entirely
- **Principle of least exposure**: Only return necessary order fields, not entire row
- **Audit logging**: Track who accessed what data and when

