  transports: [
    new winston.transports.File({ filename: 'audit.log' })
  ]
});

// Rate limiting per user
const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  keyGenerator: (req) => req.user?.userId || req.ip,
  message: { error: 'Too many requests, please try again later' }
});

// Database connection pool
const pool = mysql.createPool({
  host: process.env.DB_HOST,
  user: process.env.DB_USER,
  password: process.env.DB_PASSWORD,
  database: process.env.DB_NAME,
  waitForConnections: true,
  connectionLimit: 10
});

// Authentication middleware
const authenticate = async (req, res, next) => {
  const authHeader = req.headers.authorization;
  if (!authHeader?.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const token = authHeader.split(' ')[1];
    const decoded = jwt.verify(token, JWT_SECRET);

    // Verify user still exists and is active
    const [users] = await pool.execute(
      'SELECT user_id, role, is_active FROM users WHERE user_id = ?',
      [decoded.userId]
    );

    if (users.length === 0 || !users[0].is_active) {
      return res.status(401).json({ error: 'Account inactive or not found' });
    }

    req.user = {
      userId: users[0].user_id,
      role: users[0].role
    };
    next();
  } catch (error) {
    return res.status(401).json({ error: 'Invalid or expired token' });
  }
};

// Authorization middleware factory
const authorize = (allowedRoles) => {
  return (req, res, next) => {
    if (!allowedRoles.includes(req.user.role)) {
      auditLogger.warn({
        event: 'UNAUTHORIZED_ACCESS_ATTEMPT',
        userId: req.user.userId,
        userRole: req.user.role,
        requiredRoles: allowedRoles,
        endpoint: req.originalUrl,
        method: req.method,
        ip: req.ip,
        timestamp: new Date().toISOString()
      });
      return res.status(403).json({ error: 'Insufficient permissions' });
    }
    next();
  };
};

// Ownership verification helper
const verifyOwnershipOrAdmin = async (req, res, next) => {
  const requestedUserId = parseInt(req.params.userId, 10);
  const currentUser = req.user;

  // Input validation
  if (isNaN(requestedUserId) || requestedUserId <= 0) {
    return res.status(400).json({ error: 'Invalid user ID format' });
  }

  // Check 1: Is current user the owner?
  const isOwner = currentUser.userId === requestedUserId;

  // Check 2: Is current user an admin or support?
  const hasElevatedAccess = [ROLES.ADMIN, ROLES.SUPPORT].includes(currentUser.role);

  if (!isOwner && !hasElevatedAccess) {
    auditLogger.warn({
      event: 'HORIZONTAL_PRIVILEGE_ESCALATION_ATTEMPT',
      attackerUserId: currentUser.userId,
      targetUserId: requestedUserId,
      endpoint: req.originalUrl,
      ip: req.ip,
      timestamp: new Date().toISOString()
    });
    return res.status(403).json({ error: 'Access denied to this resource' });
  }

  req.targetUserId = requestedUserId;
  req.accessType = isOwner ? 'owner' : 'elevated';
  next();
};

// SECURE ENDPOINT: Get orders with proper authorization
app.get('/api/users/:userId/orders',
  authenticate,
  apiLimiter,
  verifyOwnershipOrAdmin,
  async (req, res) => {
    const { targetUserId, accessType, user } = req;

    try {
      // Different field access based on role
      let fields = 'order_id, product_name, quantity, total, status, created_at';
      if (user.role === ROLES.ADMIN) {
        fields += ', internal_notes, profit_margin'; // Admin-only fields
      }

      const [orders] = await pool.execute(
        `SELECT ${fields} FROM orders WHERE user_id = ? ORDER BY created_at DESC`,
        [targetUserId]
      );

      // Comprehensive audit logging
      auditLogger.info({
        event: 'ORDERS_ACCESSED',
        accessorUserId: user.userId,
        accessorRole: user.role,
        targetUserId: targetUserId,
        accessType: accessType,
        recordCount: orders.length,
        ip: req.ip,
        userAgent: req.headers['user-agent'],
        timestamp: new Date().toISOString()
      });

      res.json({
        orders,
        meta: {
          count: orders.length,
          accessedBy: accessType === 'owner' ? 'self' : `${user.role}`
        }
      });
    } catch (error) {
      console.error('Database error:', error.message);
      res.status(500).json({ error: 'Unable to retrieve orders' });
    }
  }
);

// Current user's orders shortcut (always safe)
app.get('/api/my/orders',
  authenticate,
  apiLimiter,
  async (req, res) => {
    const [orders] = await pool.execute(
      'SELECT order_id, product_name, quantity, total, status, created_at FROM orders WHERE user_id = ? ORDER BY created_at DESC',
      [req.user.userId]
    );

    res.json({ orders });
  }
);

app.listen(3000);
```

