import org.springframework.web.bind.annotation.*;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.access.AccessDeniedException;
import org.springframework.security.access.prepost.PreAuthorize;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import io.github.bucket4j.Bucket;
import java.util.Optional;
import java.util.UUID;

@RestController
@RequestMapping("/api/v1/orders")
public class ProductionOrderController {

    private static final Logger auditLog = LoggerFactory.getLogger("SECURITY_AUDIT");
    private static final Logger appLog = LoggerFactory.getLogger(ProductionOrderController.class);

    @Autowired
    private OrderRepository orderRepository;

    @Autowired
    private AuthorizationService authorizationService;

    @Autowired
    private RateLimiterService rateLimiter;

    @Autowired
    private SecurityMetricsService metricsService;

    /**
     * Get order by public UUID (not sequential ID)
     * Supports both admin access and user self-access
     */
    @GetMapping("/{orderUuid}")
    public OrderDTO getOrder(
            @PathVariable UUID orderUuid,
            @AuthenticationPrincipal UserPrincipal currentUser,
            HttpServletRequest request) {

        String clientIp = getClientIp(request);
        String requestId = UUID.randomUUID().toString();

        // Layer 1: Rate limiting per user
        if (!rateLimiter.tryConsume(currentUser.getId(), "order-access")) {
            auditLog.warn("requestId={} RATE_LIMIT_EXCEEDED userId={} ip={}",
                         requestId, currentUser.getId(), clientIp);
            metricsService.incrementRateLimitHits("order-access");
            throw new TooManyRequestsException("Too many requests. Please try again later.");
        }

        // Layer 2: Fetch order using non-enumerable UUID
        Optional<Order> orderOpt = orderRepository.findByPublicUuid(orderUuid);

        if (orderOpt.isEmpty()) {
            auditLog.info("requestId={} ORDER_NOT_FOUND orderUuid={} userId={}",
                         requestId, orderUuid, currentUser.getId());
            throw new OrderNotFoundException("Order not found");
        }

        Order order = orderOpt.get();

        // Layer 3: Authorization check with role hierarchy
        AuthorizationResult authResult = authorizationService.checkOrderAccess(
            currentUser, order, AccessType.READ);

        if (!authResult.isAuthorized()) {
            auditLog.error("requestId={} UNAUTHORIZED_ACCESS userId={} orderUuid={} ownerId={} reason={} ip={}",
                          requestId, currentUser.getId(), orderUuid, 
                          order.getUserId(), authResult.getReason(), clientIp);
            metricsService.incrementUnauthorizedAccess("order-access");

            // Alert on repeated violations
            if (metricsService.getViolationCount(currentUser.getId()) > 5) {
                alertService.sendSecurityAlert(
                    "Repeated unauthorized access attempts by user: " + currentUser.getId());
            }

            throw new AccessDeniedException("Access denied");
        }

        auditLog.info("requestId={} ORDER_ACCESSED userId={} orderUuid={} accessType={}",
                     requestId, currentUser.getId(), orderUuid, authResult.getAccessType());

        // Layer 4: Return filtered DTO based on role
        return orderMapper.toDTO(order, authResult.getAllowedFields());
    }

    /**
     * Admin-only endpoint with additional controls
     */
    @GetMapping("/admin/search")
    @PreAuthorize("hasRole('ADMIN') or hasRole('SUPPORT')")
    public Page<OrderDTO> searchOrders(
            @RequestParam(required = false) String customerId,
            @RequestParam(required = false) String status,
            @AuthenticationPrincipal UserPrincipal currentUser,
            Pageable pageable) {

        // Verify admin privileges at service layer too (defense in depth)
        if (!authorizationService.hasAdminAccess(currentUser)) {
            auditLog.error("PRIVILEGE_ESCALATION_ATTEMPT userId={} endpoint=admin/search",
                          currentUser.getId());
            throw new AccessDeniedException("Insufficient privileges");
        }

        auditLog.info("ADMIN_ORDER_SEARCH adminId={} customerId={} status={}",
                     currentUser.getId(), customerId, status);

        return orderService.searchOrders(customerId, status, pageable)
                          .map(order -> orderMapper.toDTO(order, FieldSet.ADMIN));
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}
```

