Excellent question! Multi-tenant and shared resource authorization requires a more sophisticated approach. You need to implement relationship-based access control that verifies not just ownership but also organizational membership, sharing permissions, and role-based access.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"strconv"
	"time"

	"github.com/gorilla/mux"
	_ "github.com/lib/pq"
	"golang.org/x/time/rate"
)

type Document struct {
	ID        int       `json:"id"`
	Title     string    `json:"title"`
	Content   string    `json:"content"`
	OwnerID   int       `json:"owner_id"`
	OrgID     int       `json:"org_id"`
	CreatedAt time.Time `json:"created_at"`
}

type AuthContext struct {
	UserID    int
	OrgID     int
	Roles     []string
	SessionID string
}

type contextKey string

const authContextKey contextKey = "authContext"

type Permission string

const (
	PermRead   Permission = "read"
	PermWrite  Permission = "write"
	PermDelete Permission = "delete"
	PermAdmin  Permission = "admin"
)

var (
	db      *sql.DB
	limiter = rate.NewLimiter(rate.Every(time.Second), 100)
)

// AuthorizationService handles all access control decisions
type AuthorizationService struct {
	db *sql.DB
}

func NewAuthorizationService(db *sql.DB) *AuthorizationService {
	return &AuthorizationService{db: db}
}

// CheckDocumentAccess verifies user can access document with given permission
func (as *AuthorizationService) CheckDocumentAccess(
	ctx context.Context,
	auth *AuthContext,
	docID int,
	requiredPerm Permission,
) (bool, error) {
	// Layer 1: Check if user is document owner
	var ownerID, docOrgID int
	err := as.db.QueryRowContext(ctx,
		"SELECT owner_id, org_id FROM documents WHERE id = $1",
		docID,
	).Scan(&ownerID, &docOrgID)

	if err == sql.ErrNoRows {
		return false, nil
	}
	if err != nil {
		return false, fmt.Errorf("database error: %w", err)
	}

	// Owner has full access
	if ownerID == auth.UserID {
		return true, nil
	}

	// Layer 2: Check explicit sharing permissions
	var hasExplicitAccess bool
	err = as.db.QueryRowContext(ctx,
		`SELECT EXISTS(
			SELECT 1 FROM document_shares 
			WHERE document_id = $1 
			AND user_id = $2 
			AND permission >= $3
			AND (expires_at IS NULL OR expires_at > NOW())
		)`,
		docID, auth.UserID, requiredPerm,
	).Scan(&hasExplicitAccess)

	if err != nil {
		return false, fmt.Errorf("share check error: %w", err)
	}
	if hasExplicitAccess {
		return true, nil
	}

	// Layer 3: Check organization membership with role-based access
	if docOrgID == auth.OrgID {
		for _, role := range auth.Roles {
			if role == "org_admin" {
				return true, nil
			}
			if role == "org_member" && requiredPerm == PermRead {
				// Check if document is marked as org-visible
				var isOrgVisible bool
				err = as.db.QueryRowContext(ctx,
					"SELECT org_visible FROM documents WHERE id = $1",
					docID,
				).Scan(&isOrgVisible)
				if err == nil && isOrgVisible {
					return true, nil
				}
			}
		}
	}

	return false, nil
}

// AuditLog records access attempts for security monitoring
type AuditLog struct {
	db *sql.DB
}

func (al *AuditLog) LogAccess(
	ctx context.Context,
	auth *AuthContext,
	resourceType string,
	resourceID int,
	action string,
	allowed bool,
	reason string,
) {
	_, err := al.db.ExecContext(ctx,
		`INSERT INTO audit_logs 
		(user_id, org_id, session_id, resource_type, resource_id, action, allowed, reason, ip_address, timestamp)
		VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9, NOW())`,
		auth.UserID, auth.OrgID, auth.SessionID, resourceType, resourceID, action, allowed, reason, ctx.Value("ip"),
	)
	if err != nil {
		log.Printf("Failed to write audit log: %v", err)
	}
}

// Middleware for rate limiting
func RateLimitMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if !limiter.Allow() {
			http.Error(w, "Rate limit exceeded", http.StatusTooManyRequests)
			return
		}
		next.ServeHTTP(w, r)
	})
}

// GetDocument with comprehensive authorization
func GetDocument(w http.ResponseWriter, r *http.Request) {
	auth, ok := r.Context().Value(authContextKey).(*AuthContext)
	if !ok || auth == nil {
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	vars := mux.Vars(r)
	docID, err := strconv.Atoi(vars["id"])
	if err != nil {
		http.Error(w, "Invalid document ID", http.StatusBadRequest)
		return
	}

	ctx := context.WithValue(r.Context(), "ip", r.RemoteAddr)
	authzService := NewAuthorizationService(db)
	auditLog := &AuditLog{db: db}

	// Check authorization
	allowed, err := authzService.CheckDocumentAccess(ctx, auth, docID, PermRead)
	if err != nil {
		log.Printf("Authorization check failed: %v", err)
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	if !allowed {
		// Log unauthorized access attempt
		auditLog.LogAccess(ctx, auth, "document", docID, "read", false, "access_denied")
		// Return 404 instead of 403 to prevent resource enumeration
		http.Error(w, "Document not found", http.StatusNotFound)
		return
	}

	// Log successful access
	auditLog.LogAccess(ctx, auth, "document", docID, "read", true, "authorized")

	// Fetch document
	var doc Document
	err = db.QueryRowContext(ctx,
		"SELECT id, title, content, owner_id, org_id, created_at FROM documents WHERE id = $1",
		docID,
	).Scan(&doc.ID, &doc.Title, &doc.Content, &doc.OwnerID, &doc.OrgID, &doc.CreatedAt)

	if err != nil {
		http.Error(w, "Document not found", http.StatusNotFound)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("X-Content-Type-Options", "nosniff")
	w.Header().Set("Cache-Control", "private, no-store")
	json.NewEncoder(w).Encode(doc)
}
```

**Defense in Depth Layers**:

1. **Multi-Level Authorization Checks**:
```go
