if ownerID == auth.UserID { return true, nil }

// Layer 2: Explicit sharing with expiration
SELECT EXISTS(...) FROM document_shares WHERE expires_at > NOW()

// Layer 3: Organization role-based access
if docOrgID == auth.OrgID && hasRole("org_admin") { return true, nil }
```

2. **Security Response Obfuscation**:
```go
